120→async function migrateBeadsToKspec(cwd: string): Promise<{ success: boolean; migrated: number; error?: string }> {
121→  try {
122→    // 1. Read all beads tasks via bd list --json
123→    const listResult = await spawnCommand('bd', ['list', '--json'], cwd)
124→    if (listResult.code !== 0) {
125→      return { success: false, migrated: 0, error: `Failed to read beads tasks: ${listResult.stderr}` }
126→    }
127→
128→    let beadsTasks: Array<Record<string, unknown>> = []
129→    try {
130→      const parsed = JSON.parse(listResult.stdout)
131→      beadsTasks = Array.isArray(parsed) ? parsed : (parsed.issues ?? parsed.tasks ?? [])
132→    } catch {
133→      // No tasks to migrate, or empty output — that's fine
134→      beadsTasks = []
135→    }
136→
137→    // 2. Initialize kspec
138→    const gitDir = join(cwd, '.git')
139→    if (!existsSync(gitDir)) {
140→      const gitResult = await spawnCommand('git', ['init'], cwd)
141→      if (gitResult.code !== 0) {
142→        return { success: false, migrated: 0, error: `Failed to init git: ${gitResult.stderr}` }
143→      }
144→      await spawnCommand('git', ['config', 'user.name', 'kspec'], cwd)
145→      await spawnCommand('git', ['config', 'user.email', 'kspec@local'], cwd)
146→      await spawnCommand('git', ['commit', '--allow-empty', '-m', 'init'], cwd)
147→    }
148→
149→    const initResult = await spawnCommand('kspec', ['init', '.', '--name', 'Project'], cwd)
150→    if (initResult.code !== 0) {
151→      return { success: false, migrated: 0, error: `kspec init failed: ${initResult.stderr}` }
152→    }
153→
154→    // Run setup + generate agents instructions
155→    await spawnCommand('kspec', ['setup'], cwd)
156→    await spawnCommand('kspec', ['agents', 'generate'], cwd)
157→
158→    // 3. Ensure daemon is running for task creation
159→    let daemonReady = false
160→    const healthCheck = await fetch('http://localhost:3456/api/health').catch(() => null)
161→    if (healthCheck?.ok) {
162→      daemonReady = true
163→    } else {
164→      const proc = spawn('kspec', ['serve', 'start', '--daemon'], {
165→        cwd,
166→        env: getExecOptions().env,
167→        detached: true,
168→        stdio: 'ignore'
169→      })
170→      proc.unref()
171→      for (let i = 0; i < 10; i++) {
172→        await new Promise(r => setTimeout(r, 500))
173→        const check = await fetch('http://localhost:3456/api/health').catch(() => null)
174→        if (check?.ok) { daemonReady = true; break }
175→      }
176→    }
177→
178→    // 4. Migrate each task to kspec
179→    let migrated = 0
180→    if (daemonReady && beadsTasks.length > 0) {
181→      // Register project with daemon
182→      await fetch('http://localhost:3456/api/projects', {
183→        method: 'POST',
184→        headers: { 'Content-Type': 'application/json' },
185→        body: JSON.stringify({ path: cwd })
186→      }).catch(() => {})
187→
188→      for (const task of beadsTasks) {
189→        try {
190→          // Map beads priority (0-4, 0=critical) to kspec priority (1-5, 1=highest)
191→          const beadsPriority = typeof task.priority === 'number' ? task.priority : 2
192→          const kspecPriority = Math.min(5, Math.max(1, beadsPriority + 1))
193→
194→          // Map beads type to kspec type
195→          const beadsType = String(task.issue_type ?? task.type ?? 'task')
196→          const kspecType = beadsType === 'feature' ? 'task' : (['bug', 'task', 'epic'].includes(beadsType) ? beadsType : 'task')
197→
198→          // Map beads status to kspec status
199→          const beadsStatus = String(task.status ?? 'open')
200→          let kspecStatus: string | undefined
201→          if (beadsStatus === 'in_progress') kspecStatus = 'in_progress'
202→          else if (beadsStatus === 'closed') kspecStatus = 'completed'
203→          // 'open' maps to 'pending' which is the default — no need to set
204→
205→          const res = await fetch('http://localhost:3456/api/tasks', {
206→            method: 'POST',
207→            headers: {
208→              'Content-Type': 'application/json',
209→              'X-Kspec-Dir': cwd
210→            },
211→            body: JSON.stringify({
212→              title: String(task.title ?? ''),
213→              description: task.description ? String(task.description) : undefined,
214→              priority: kspecPriority,
215→              type: kspecType,
216→              status: kspecStatus,
217→              tags: [`migrated-from:${String(task.id ?? '')}`]
218→            })
219→          })
220→          if (res.ok) migrated++
221→        } catch {
222→          // Skip individual task failures
223→        }
224→      }
225→    }
226→
227→    // 5. Stop beads daemon and remove .beads/ directory
228→    const beadsDir = join(cwd, '.beads')
229→    if (existsSync(beadsDir)) {
230→      // Stop beads daemon first (releases lock files)
231→      await spawnCommand('bd', ['daemon', '--stop'], cwd).catch(() => {})
232→      // Small delay for daemon to release files
233→      await new Promise(r => setTimeout(r, 500))
234→      const { rmSync } = await import('fs')
235→      rmSync(beadsDir, { recursive: true, force: true })
236→    }
237→
238→    // 6. Update CLAUDE.md to kspec instructions
239→    installTaskInstructions(cwd, 'kspec')
240→
241→    return { success: true, migrated }
242→  } catch (e) {
243→    return { success: false, migrated: 0, error: String(e) }
244→  }
245→}
